+export type DurationObservation = { duration: number, recordedAt: number }
+
+export function smoothDurations(observations: DurationObservation[], smoothing: 'latest' | 'average' | 'p95' | 'median'): number {
+  if (!observations.length) return 0
+  if (smoothing === 'latest') return observations.reduce((latest, observation) => observation.recordedAt > latest.recordedAt ? observation : latest).duration
+  const values = observations.map(observation => observation.duration).sort((a, b) => a - b)
+  if (smoothing === 'average') return Math.round(values.reduce((sum, value) => sum + value, 0) / values.length)
+  if (smoothing === 'p95') return values[Math.ceil(0.95 * values.length) - 1]
+  const middle = Math.floor(values.length / 2)
+  return values.length % 2 ? values[middle] : Math.floor((values[middle - 1] + values[middle]) / 2)
